var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위─── 수리 불───가.</color>","JPN":"<color=#ff3636>損傷部位───修理不───可。</color>","ENG":"<color=#ff3636>Damage... beyond repair...</color>","TWN":"<color=#ff3636>破損部位……無法……修復。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>시스템─── 다운──.</color>","JPN":"<color=#ff3636>システム───ダウン──。</color>","ENG":"<color=#ff3636>System... down...</color>","TWN":"<color=#ff3636>系統……下線……</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"지, 지금입니다요!","JPN":"い、今でやんす！","ENG":"N-now!","TWN":"就、就是現在！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"자폭 시퀸스에 들어가기 전에 AI 모듈이 탑재된 머리 부분을 파괴하는 겁니다요!","JPN":"自爆シークエンスに入る前に、AIモジュールが搭載された頭部を破壊するでやんす！","ENG":"Smash its head where the AI module is before it activates its self-destruct sequence!","TWN":"在它開啟自爆程式之前，摧毀裝有AI模組的頭部！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"알고 있어!!","JPN":"わかってる！！","ENG":"I got it!!","TWN":"我知道！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"한 번 당하지, 두 번은 안 당한다고!!","JPN":"二度はやられない！！","ENG":"It won't fool me twice!!","TWN":"我不會再吃第二吃虧的！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히익!?","JPN":"キヒイッ！？","ENG":"Eep...?!","TWN":"吱？！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"하, 한 방에 목을 댕강 해버렸습니다요……!!","JPN":"い、一発で首を斬っちゃったでやんす……！！","ENG":"Y-you decapitated it with one blow...!!","TWN":"一、一拳就把頭給打下來了……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"좋아! 적성 개체의 제압을 완료했다!","JPN":"よし！　敵性個体の制圧を完了した！","ENG":"All right! Hostile eliminated!","TWN":"很好！已完成對敵人個體的壓制！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"작업조! 다른 파츠는 상관없으니까 동력원만 분리해서 함선에 실어 둬!","JPN":"作業組！　他のパーツはいいから、動力源だけ切り離して艦船に乗せておけ！","ENG":"Disassembly team! Don't care about the other parts, but make sure to disconnect its power source and load it on the ship!","TWN":"拆卸組！其他零件不用管，分離動力源，搬到艦船上來！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"다들 수고 많았다! 해체 작업이 끝나면 현실로 복귀한다!","JPN":"みんな、ご苦労だったな！　解体作業が終わったら現実に復帰するぞ！","ENG":"Great job, everyone! Once the dismantling is done, we head back to the Normalside!","TWN":"大家辛苦了！拆解工作結束後，我們就返回現世！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"오오~!","JPN":"おお～！","ENG":"Ooh!","TWN":"噢噢～！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"요 귀여운 녀석이 차세대 동력원, 아베스타 드라이브일지도 모른다니!","JPN":"この可愛いやつが次世代動力源、アヴェスター・ドライブなのかもしれないんだって！？","ENG":"So this cute one could be the next-gen power source, Avesta Drive!","TWN":"說不定，這個可愛的傢伙就是次世代動力源了，阿貝斯塔引擎！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"킥킥! 훌륭합니다요! 완벽합니다요! 원더풀입니다요!","JPN":"ククッ！　素晴らしいでやんす！　完璧でやんす！　ワンダブルでやんすよ！","ENG":"Keke! Excellent! Perfect! Wonderful!","TWN":"嘻嘻！優秀！完美！超讚的！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"대체 뭐가 귀엽다는 거야?","JPN":"これのどこが可愛いんだ？","ENG":"What's so cute about it?","TWN":"這有什麼可愛的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"어딜 봐도 그냥 딱정벌레 뱃속에서 꺼낸 고철 덩어리잖아.","JPN":"どう見てもただカブトムシの腹から出した鉄くずだろう。","ENG":"It just looks like scrap metal taken out from the beetle's stomach.","TWN":"怎麼看，都只是從甲殼蟲裡取出來的一塊廢鐵。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키이힉……!!","JPN":"キイヒッ……！！","ENG":"...Eek?!","TWN":"吱……！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"원래 지식이라는 건, 알면 알수록 더 많은 게 보이는 겁니다요!","JPN":"人というのは博識であるほど、見えてくるものが多いのでやんす！","ENG":"Knowledge is said to reveal more to those who know more!","TWN":"知道的越多，看到的就越多！知識就是這樣的！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"요 안에 얼마나 무궁무진한 가능성이 숨겨져 있을지 상상이나 해보셨습니까요?","JPN":"この中にどんな可能性が隠れているか、想像したことはあるでやんすか？","ENG":"Have you ever imagined the endless possibilities that could be hiding inside here?","TWN":"你有沒有想像過裡面隱藏著怎樣無限的可能性？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 전대장님의 허접한 상상력으로는 무리겠지만 말입니다요~","JPN":"ま、戦隊長のつまんない想像力じゃあ、無理でやんすけどね～","ENG":"Then again, I don't think that's possible with your poor imagination!","TWN":"好吧，以戰隊長可憐的腦容量來說，這大概是不可能的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"아니, 뭐야!?","JPN":"な、何だと！？","ENG":"Hey, what?!","TWN":"嘿，什麼？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"……우갸아악!!","JPN":"……うぎゃああっ！！","ENG":"...Uwaaagh!!","TWN":"……嗚哇啊啊！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"때릴 때 때리더라도, 비스트 클로는 벗고 때리는 겁니다요!","JPN":"殴るのはいいですけど、ビーストクローは外してからにしてほしいでやんす！","ENG":"If you're going to hit me, then at least take off Beast Claw before you do!","TWN":"你要打我頭可以，先、先把那個魔獸爪脫下來再說啊！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"맞을 짓 했다는 건 아네? 더 괘씸하잖아?","JPN":"殴られるようなことをしたって自覚はあるのか。なおさらたちが悪いな。","ENG":"So you do know what you did was wrong. That pisses me off so much more.","TWN":"明知故犯，不是更可惡嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키이이…….","JPN":"キイイ……","ENG":"Eep...","TWN":"吱……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"……앨리스 전대장님.","JPN":"……アリス戦隊長。","ENG":"...Commander Alice.","TWN":"……艾莉絲戰隊長。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 비스트 클로는 괜찮으십니까?","JPN":"そのビーストクロー、大丈夫ですか？","ENG":"How's Beast Claw doing?","TWN":"你對現在的魔獸爪還滿意嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장님께 맞게 조정을 하긴 했지만, 어디까지나 그건 라이오넬 전대장님의 고유무장…….","JPN":"戦隊長に合わせて調整はしてありますが、それはあくまでもライオネル戦隊長の固有武装……","ENG":"I adjusted it to fit you, but it is still Commander Lionel's Unique Gear...","TWN":"雖然為了適應戰隊長進行了調整，但終究是萊諾戰隊長的專屬裝備……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"당신에게 맞는 무장이 아니라서 신체에 부담을 줄 겁니다요.","JPN":"あなた用の武装ではないので、体に負担を与えるはずでやんす。","ENG":"Since it's not something made for you, it will put a strain on your body.","TWN":"不適合的武器，會給身體帶來壓力。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그런데도 그렇게 능숙하게 다루다니…….","JPN":"にもかかわらず、それほど上手に扱うなんて……","ENG":"And yet, you seem to be using it like it's an extension of yourself...","TWN":"但你卻好像一直沒事一樣……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐야, 그런 걸 신경쓰고 있었어?","JPN":"何だ、そんなことを気にしていたのか？","ENG":"Huh? Was that on your mind this whole time?","TWN":"什麼啊，你很在意？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"하핫! 이게 다 매일매일 트레이닝을 빼먹지 않아서 그런 거 아니겠냐?","JPN":"ははっ！　これは日々のトレーニングのおかげだ！","ENG":"Hah hah! It's because I never forget to lift weights every day!","TWN":"哈哈！那是因為我每天都有確實訓練喔？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"말 나온 김에 너도 스쿼트 좀 하라고. ","JPN":"話が出たついでだ、お前もスクワットくらいしたらどうだ？ ","ENG":"While we're on the topic, you should do some squats with me.","TWN":"我運動的時候，你也可以跟著做下深蹲嘛。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이이익!! 운동은 싫습니다요!!","JPN":"ギギギッ！！　運動はイヤでやんす！！","ENG":"Eeeek! I hate exercising!!","TWN":"不不不！！我討厭運動！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 그래도 신경 써줘서 고맙다.","JPN":"ま、でも気使ってくれてありがとな。","ENG":"But thanks for your concern.","TWN":"嗯，還是謝謝你的關心。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"돌아가면, 해바라기 씨 초콜렛 사줄게.","JPN":"帰ったら、ヒマワリの種のチョコレートを買ってやる。","ENG":"Once we get back, I'll treat you to some chocolate-covered sunflower seeds.","TWN":"等我們回來後，我請你吃葵花籽巧克力。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"해바라기 씨!","JPN":"ヒマワリの種！","ENG":"Sunflower seeds!","TWN":"葵花籽！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"달콤합니다요! 고소합니다요! 대만족입니다요!","JPN":"甘いでやんす！　香ばしいでやんす！　大満足でやんす！","ENG":"They're sweet! Savory! I love them!","TWN":"甜甜的！香香的！超級喜歡！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"야크샤 전대장님. 화물 적재가 완료되었습니다.","JPN":"ヤクシャー戦隊長。貨物積載が完了しました。","ENG":"Yaksha Commander. We've loaded the cargo onto the ship.","TWN":"夜叉戰隊長。貨物裝載已完成。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"현실로 부상하시겠습니까?","JPN":"現実に浮上しますか？","ENG":"Shall we begin our return to the Normalside?","TWN":"是否躍出現世？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"응. 부탁할게, 모네카.","JPN":"ああ。頼む、モネカ。","ENG":"Yes. Get us back up, Moneka.","TWN":"嗯。拜託了，莫奈卡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이터니움 드라이브, 출력 전개!","JPN":"エタニウムドライブ、出力全開！","ENG":"The Eternium Drive is at full power!","TWN":"永恆之金驅動器，馬力全開！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"야크샤 전대. 현실로 부상합니다!","JPN":"ヤクシャー戦隊。現実に浮上します！","ENG":"The Yaksha Division, returning to the Normalside!","TWN":"夜叉戰隊。開始躍出！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"함 내에 야크샤 전대에 전달 드립니다.","JPN":"艦内のヤクシャー戦隊にお知らせいたします。","ENG":"To all the Yaksha Division members on board.","TWN":"艦船內的全體夜叉戰隊員請注意。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"본 함. 현실로 무사히……","JPN":"本艦。無事現実に……","ENG":"The ship has safely made it back to the Normal–","TWN":"本艦。安全回到現實……"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"제기랄!! 이게 무슨 일이야, 모네카……!!","JPN":"くそ！！　どういうことだ、モネカ……！！","ENG":"Argh!! What's going on, Moneka...?!","TWN":"可惡！！這是怎麼回事，莫奈卡……！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"본 함! 정체불명의 적기로부터 공격받고 있습니다!","JPN":"本艦！　正体不明の敵機から攻撃されています！","ENG":"The ship! It's being attacked by an unknown enemy!","TWN":"艦船遭到了不明敵機的攻擊！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"무슨 소리야!? 정체불명의 적기라고!?","JPN":"なに！？　正体不明の敵機だと！？","ENG":"What? An unknown enemy?","TWN":"你在說什麼？！不明敵機？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"여긴 현실세계잖아!?","JPN":"ここはノーマルサイドだろう！？","ENG":"But we're back in the Normalside!","TWN":"我們不是已經回到現世了嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"식별신호 확인 중……!","JPN":"識別信号を確認中……！","ENG":"Checking the identification signal...!","TWN":"正在檢查識別訊號……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"식별신호……. 관리국 전략위성……?","JPN":"識別信号……管理局の戦略衛星……？","ENG":"The signal is... an Administration strategic satellite...?","TWN":"識別訊號……管理局戰略衛星……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐? 전략위성이 왜……?","JPN":"は？　戦略衛星がどうして……？","ENG":"What? Why would a strategic satellite...?","TWN":"什麼？戰略衛星為什麼……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"전략위성! 대기권 너머에서 본 함에 폭격을 가하고 있습니다!","JPN":"戦略衛星！　大気圏の向こうから本艦に爆撃中です！","ENG":"The strategic satellite! It's bombarding us from beyond the atmosphere!","TWN":"戰略衛星！正在從大氣層之外轟炸這艘艦船！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"3차 폭격 옵니다!!","JPN":"3次爆撃、来ます！！","ENG":"Third round of bombardment on its way!!","TWN":"第三次轟炸來了！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"3번 엔진, 이터니움 드라이브 파괴되었습니다! 출력 저하됩니다!","JPN":"3番エンジン、エタニウムドライブが爆破されました！　出力が低下します！","ENG":"Engine No. 3's Eternium Drive is destroyed! Output declining!","TWN":"3號永恆之金驅動器已被摧毀！輸出下降！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"모네카! 비상 착륙 절차!!","JPN":"モネカ！　非常着陸モード！！","ENG":"Moneka! Proceed with emergency landing mode!","TWN":"莫奈卡！啟動緊急迫降程式！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"명령 확인! 비상 착륙 절차에 돌입합니다!","JPN":"命令を確認！　非常着陸モードに入ります！","ENG":"Orders confirmed! Preparing for an emergency landing!","TWN":"確認命令！緊急迫降程式啟動！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"착륙한다!! 모두 꽉 잡아!!","JPN":"着陸する！！　みんな、しっかり掴まれ！！","ENG":"Brace for impact! Hold on tight!!","TWN":"大家抓緊了！！準備好應對衝擊！！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우갸아아아악……!!","JPN":"うぎゃああああっ……！！","ENG":"Uwaaaaaagh...!!","TWN":"嗚哇啊啊啊……！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장!! 추락 속도가 안 줄어!!","JPN":"くそ！！　墜落速度が落ちないぞ！！","ENG":"Dammit!! Our speed isn't decreasing!!","TWN":"可惡！！墜落速度沒有減緩！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이대로 가다간, 지면에 거의 수직으로 내리꽂히겠어!","JPN":"このままじゃ、地面にほぼ垂直で激突する！","ENG":"At this rate, we'll be nosediving into the ground!!","TWN":"再這樣下去，會直直插入地面的！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"어떻게든 해야 해!!","JPN":"何とかしないと！！","ENG":"I must do something!!","TWN":"我們必須做點什麼！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"모네카! 램프도어 개방!","JPN":"モネカ！　ランプドア開放！","ENG":"Moneka! Open the cargo door!","TWN":"莫奈卡！打開艙門！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네!? 무슨 말씀이세요, 전대장님!!","JPN":"はい！？　どういうことですか、戦隊長！！","ENG":"Huh?! What are you talking about, Commander?!","TWN":"嗯？！你說什麼，戰隊長！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"시간이 없어!! 내 능력으로 함선의 충돌 각도를 비틀겠다!!","JPN":"時間がない！！　アタシの能力で艦船の衝突角度を変える！！","ENG":"There's no time!! I'm going to use my power to tilt the collision angle!","TWN":"沒時間了！！我會用我的能力扭轉艦船的碰撞角度！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"최대한 안전한 각도로 비상 착륙시켜야 해!!","JPN":"なるべく安全な角度で非常着陸させないと！！","ENG":"The ship needs to land at the safest possible angle!!","TWN":"盡可能地以安全角度緊急迫降！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그렇지만 전대장님은……!?","JPN":"ですが、戦隊長は……！？","ENG":"But what about you, Commander...?!","TWN":"但是戰隊長你……？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"빨리 열어!!","JPN":"早く開けろ！！","ENG":"Just open it!!","TWN":"快點打開！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"좋아, 해보는 거야!!","JPN":"よし、やるぞ！！","ENG":"Okay, let's do this!!","TWN":"好，那就試試吧！！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"간다아아아아아아아아아아아아아───────!!","JPN":"行くぞおおおおおおおおおおおおお───────！！","ENG":"I got thiiiiiis!!","TWN":"我可以的──────！！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};